<?php $pageTitle='المستخدمون'; include __DIR__.'/includes/header.php'; if($_SESSION['role']!=='super_admin'){header('Location:index.php');exit;} $pdo=getDB();
if($_SERVER['REQUEST_METHOD']==='POST' && adminTableExists($pdo,'users')){ if(!empty($_POST['password'])){$pdo->prepare('INSERT INTO users (username,email,password,role) VALUES (?,?,?,?)')->execute([trim($_POST['username']),trim($_POST['email']),password_hash($_POST['password'], PASSWORD_DEFAULT),$_POST['role']]);}}
$items=adminTableExists($pdo,'users')?adminFetchAll($pdo,'SELECT id,username,email,role,created_at FROM users ORDER BY id DESC'):[];?>
<div class="container-fluid"><h1 class="h4">إدارة المستخدمين والصلاحيات</h1><form method="post" class="card card-body mb-3"><div class="row g-2"><div class="col"><input class="form-control" name="username" placeholder="username" required></div><div class="col"><input class="form-control" name="email" type="email" placeholder="email" required></div><div class="col"><input class="form-control" name="password" type="password" placeholder="password" required></div><div class="col"><select name="role" class="form-select"><option value="editor">editor</option><option value="admin">admin</option><option value="super_admin">super_admin</option></select></div><div class="col"><button class="btn btn-primary">إضافة</button></div></div></form><table class="table table-sm table-bordered"><tr><th>#</th><th>Username</th><th>Email</th><th>Role</th></tr><?php foreach($items as $i):?><tr><td><?php echo $i['id'];?></td><td><?php echo escape($i['username']);?></td><td><?php echo escape($i['email']);?></td><td><?php echo escape($i['role']);?></td></tr><?php endforeach;?></table></div>
<?php include __DIR__.'/includes/footer.php'; ?>
